import React, { useState, useEffect } from 'react';
import { expenseService, seasonService, pondService } from '../../services/api';
import '../../styles/dashboard.css';

export const StaffExpenses = () => {
  const [expenses, setExpenses] = useState([]);
  const [seasons, setSeasons] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);
  const [selectedSeasonId, setSelectedSeasonId] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({
    categoryId: 1,
    amount: '',
    expenseDate: '',
    note: '',
  });

  useEffect(() => {
    fetchData();
  }, []);

  useEffect(() => {
    if (selectedSeasonId) {
      fetchExpenses(selectedSeasonId);
    }
  }, [selectedSeasonId]);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [seasonsRes] = await Promise.all([
        seasonService.getAllSeasons(),
        pondService.getAllPonds(),
      ]);

      setSeasons(seasonsRes.data.data || []);

      if (seasonsRes.data.data?.length > 0) {
        setSelectedSeasonId(seasonsRes.data.data[0].season_id);
      }
    } catch (err) {
      setError('Láŧi tášĢi dáŧŊ liáŧu');
    } finally {
      setLoading(false);
    }
  };

  const fetchExpenses = async (seasonId) => {
    try {
      const response = await expenseService.getExpensesBySeasonId(seasonId);
      setExpenses(response.data.data || []);
    } catch (err) {
      setError('Láŧi tášĢi danh sÃĄch chi phÃ­');
    }
  };

  const categories = [
    { id: 1, name: 'TháŧĐc Än' },
    { id: 2, name: 'Thuáŧc / Vi sinh' },
    { id: 3, name: 'Äiáŧn nÆ°áŧc' },
    { id: 4, name: 'NhÃĒn cÃīng' },
    { id: 5, name: 'Chi phÃ­ khÃĄc' },
  ];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);
    setSuccess(null);

    try {
      await expenseService.createExpense({
        season_id: selectedSeasonId,
        category_id: parseInt(formData.categoryId),
        amount: parseFloat(formData.amount),
        expense_date: formData.expenseDate,
        note: formData.note,
      });
      setSuccess('TášĄo yÃŠu cáš§u chi phÃ­ thÃ nh cÃīng');
      setShowModal(false);
      fetchExpenses(selectedSeasonId);
      setFormData({ categoryId: 1, amount: '', expenseDate: '', note: '' });
    } catch (err) {
      setError('Láŧi tášĄo yÃŠu cáš§u chi phÃ­');
    }
  };

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center" style={{ minHeight: '400px' }}>
          <div className="spinner"></div>
        </div>
      </div>
    );
  }

  const pendingExpenses = expenses.filter((e) => e.status === 'PENDING');
  const approvedExpenses = expenses.filter((e) => e.status === 'APPROVED');
  const rejectedExpenses = expenses.filter((e) => e.status === 'REJECTED');

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>ð° YÃŠu cáš§u chi phÃ­</h1>
        <p>TášĄo vÃ  theo dÃĩi yÃŠu cáš§u chi phÃ­ (khÃīng tháŧ duyáŧt)</p>
      </div>

      {error && <div className="alert alert-error">{error}</div>}
      {success && <div className="alert alert-success">{success}</div>}

      <div style={{ marginBottom: '20px' }}>
        <label style={{ marginRight: '10px', fontWeight: 600 }}>Cháŧn mÃđa váŧĨ:</label>
        <select
          value={selectedSeasonId || ''}
          onChange={(e) => setSelectedSeasonId(parseInt(e.target.value))}
          style={{ padding: '8px 12px', borderRadius: '6px', border: '1px solid #e5e7eb' }}
        >
          {seasons.map((season) => (
            <option key={season.season_id} value={season.season_id}>
              {season.season_name}
            </option>
          ))}
        </select>
      </div>

      {/* Stats */}
      <div className="stats-grid" style={{ marginBottom: '40px' }}>
        <div className="stat-card">
          <div className="stat-icon" style={{ backgroundColor: '#fef3c7' }}>
            âģ
          </div>
          <div className="stat-content">
            <p className="stat-label">Cháŧ duyáŧt</p>
            <p className="stat-value">{pendingExpenses.length}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ backgroundColor: '#dcfce7' }}>
            â
          </div>
          <div className="stat-content">
            <p className="stat-label">ÄÃĢ duyáŧt</p>
            <p className="stat-value">{approvedExpenses.length}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ backgroundColor: '#fee2e2' }}>
            â
          </div>
          <div className="stat-content">
            <p className="stat-label">TáŧŦ cháŧi</p>
            <p className="stat-value">{rejectedExpenses.length}</p>
          </div>
        </div>
      </div>

      <div className="table-container">
        <div className="table-header">
          <h2>Danh sÃĄch yÃŠu cáš§u chi phÃ­ cáŧ§a tÃīi</h2>
          <button className="btn btn-primary" onClick={() => setShowModal(true)}>
            â TášĄo yÃŠu cáš§u
          </button>
        </div>

        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>NgÃ y</th>
                <th>Danh máŧĨc</th>
                <th>Sáŧ tiáŧn</th>
                <th>Ghi chÃš</th>
                <th>TrášĄng thÃĄi</th>
              </tr>
            </thead>
            <tbody>
              {expenses.length > 0 ? (
                expenses.map((expense) => (
                  <tr key={expense.expense_id}>
                    <td>{new Date(expense.expense_date).toLocaleDateString('vi-VN')}</td>
                    <td>
                      {categories.find((c) => c.id === expense.category_id)?.name ||
                        'KhÃĄc'}
                    </td>
                    <td><strong>{expense.amount?.toLocaleString('vi-VN')} Ä</strong></td>
                    <td>{expense.note}</td>
                    <td>
                      <span
                        className={`status-badge ${
                          expense.status === 'APPROVED'
                            ? 'status-active'
                            : expense.status === 'REJECTED'
                            ? 'status-inactive'
                            : 'status-pending'
                        }`}
                      >
                        {expense.status === 'APPROVED' && 'â ÄÃĢ duyáŧt'}
                        {expense.status === 'PENDING' && 'âģ Cháŧ duyáŧt'}
                        {expense.status === 'REJECTED' && 'â TáŧŦ cháŧi'}
                      </span>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="5" style={{ textAlign: 'center', padding: '20px' }}>
                    ChÆ°a cÃģ yÃŠu cáš§u chi phÃ­ nÃ o
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="modal" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2>â TášĄo yÃŠu cáš§u chi phÃ­</h2>

            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Danh máŧĨc</label>
                <select
                  value={formData.categoryId}
                  onChange={(e) =>
                    setFormData({ ...formData, categoryId: e.target.value })
                  }
                  required
                >
                  {categories.map((cat) => (
                    <option key={cat.id} value={cat.id}>
                      {cat.name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Sáŧ tiáŧn (Ä)</label>
                  <input
                    type="number"
                    step="0.01"
                    value={formData.amount}
                    onChange={(e) => setFormData({ ...formData, amount: e.target.value })}
                    required
                  />
                </div>

                <div className="form-group">
                  <label>NgÃ y chi</label>
                  <input
                    type="date"
                    value={formData.expenseDate}
                    onChange={(e) =>
                      setFormData({ ...formData, expenseDate: e.target.value })
                    }
                    required
                  />
                </div>
              </div>

              <div className="form-group">
                <label>Ghi chÃš</label>
                <textarea
                  value={formData.note}
                  onChange={(e) => setFormData({ ...formData, note: e.target.value })}
                  placeholder="MÃī tášĢ chi phÃ­..."
                />
              </div>

              <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
                <button type="submit" className="btn btn-primary" style={{ flex: 1 }}>
                  ðū TášĄo yÃŠu cáš§u
                </button>
                <button
                  type="button"
                  className="btn btn-secondary"
                  style={{ flex: 1 }}
                  onClick={() => setShowModal(false)}
                >
                  â Háŧ§y
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffExpenses;
